// Transforma dados do Google Sheets pro formato do Supabase
// Filtra linhas sem email

const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;

  // Pega email de qualquer variacao de nome de coluna
  const email = (data.Email || data.email || '').toString().trim().toLowerCase();

  // Pular linhas sem email valido
  if (!email || !email.includes('@')) {
    continue;
  }

  results.push({
    json: {
      empresa: (data.Empresa || data.empresa || '').toString().trim(),
      cnpj: (data.CNPJ || data.cnpj || '').toString().trim(),
      uf: (data.UF || data.uf || '').toString().trim().toUpperCase(),
      contato_comprador: (data.Contato || data.contato || '').toString().trim(),
      email: email,
      origem: 'importacao',
      email_valido: true,
      ativo: true
    }
  });
}

return results;
